import{_ as a,o as e,c as i,e as t}from"./app.2ab19930.js";const h={},d=t('<h1 id="\u65C5\u884C" tabindex="-1"><a class="header-anchor" href="#\u65C5\u884C" aria-hidden="true">#</a> \u65C5\u884C</h1><p><strong>\u201C\u4E07\u91CC\u8E40\u8E9E\uFF0C\u4EE5\u6B64\u4E3A\u5F52\u3002\u201D\u2014\u2014\u4F59\u79CB\u96E8</strong></p><h2 id="\u53A6\u95E8" tabindex="-1"><a class="header-anchor" href="#\u53A6\u95E8" aria-hidden="true">#</a> \u53A6\u95E8</h2><h3 id="day-1-2022-01-16" tabindex="-1"><a class="header-anchor" href="#day-1-2022-01-16" aria-hidden="true">#</a> Day 1\uFF082022/01/16\uFF09</h3><p>\u6BCF\u4E00\u5EA7\u57CE\u5E02\u90FD\u6709\u5C5E\u4E8E\u4ED6\u7684\u7075\u9B42\uFF0C\u90FD\u6709\u5C5E\u4E8E\u4ED6\u7684\u5E95\u8272\u3002</p><p>\u4E0D\u540C\u4E8E\u957F\u6C99\u9AD8\u697C\u6797\u7ACB\u7684\u73B0\u4EE3\u5316\u90FD\u5E02\u98CE\uFF0C\u53A6\u95E8\u663E\u5F97\u6709\u4E9B\u843D\u540E\uFF0C\u4E00\u8DEF\u4E0A\uFF0C\u9664\u4E86\u53CC\u5B50\u5854\u76F4\u63D2\u4E91\u9704\uFF0C\u51E0\u4E4E\u6CA1\u6709\u770B\u89C1\u4EF0\u5934\u4ECD\u4E0D\u80FD\u53CA\u7684\u5927\u53A6\u9AD8\u697C\uFF0C\u76F8\u53CD\uFF0C\u8DEF\u8FB9\u6392\u6EE1\u4E86\u5E73\u623F\u3002\u9713\u8679\u706F\u6761\u5728\u94A2\u67B6\u4E0A\u7F16\u7EC7\u51FA\u62F1\u95E8\u7684\u8F6E\u5ED3\uFF0C\u95EA\u70C1\u7684\u5149\u70B9\u70B9\u7F00\u7740\u591C\u8272\u91CC\u7684\u6C99\u5761\u5C3E\uFF0C\u4EBA\u7FA4\u4ECE\u88C5\u6F62\u7CBE\u81F4\u7684\u5E97\u91CC\u8FDB\u8FDB\u51FA\u51FA\uFF0C\u4E00\u5207\u663E\u5F97\u4ECE\u5BB9\u4E0D\u8FEB\u3002\u53A6\u95E8\u4EBA\uFF0C\u4F3C\u4E4E\u662F\u5F88\u61C2\u751F\u6D3B\u7684\u3002</p><div style="text-align:center;"><img alt="\u5927\u6D77\u4E0E\u53CC\u5B50\u5854" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/xiamen_day1_1.jpg" width="60%" height="60%"></div><p>\u8BBA\u5EFA\u7B51\uFF0C\u957F\u6C99\u9664\u4E86\u73B0\u4EE3\u5316\u7684\u6469\u5929\u5927\u53A6\uFF0C\u8FD8\u6709\u4E0E\u8336\u989C\u60A6\u8272\u4E00\u81F4\u7684\u53E4\u8272\u53E4\u9999\u3002\u4F46\u53A6\u95E8\u7684\u88C5\u6F62\uFF0C\u4F7F\u4ED6\u770B\u8D77\u6765\u4E0D\u50CF\u662F\u7ECF\u6D4E\u7279\u533A\uFF08\u6216\u8BB8\u662F\u8FD8\u6CA1\u8D70\u5230\u53A6\u95E8\u7684\u7E41\u534E\u5730\u6BB5\uFF09\uFF0C\u800C\u662F\u4E00\u5EA7\u6EE8\u6D77\u5C0F\u57CE\u3002\u6D77\u6EE9\u4E0A\u7684\u4EBA\u6C89\u6D78\u5728\u6D77\u98CE\u4E2D\uFF0C\u629A\u6478\u7740\u6D77\u6D6A\u6253\u8D77\u7684\u767D\u8272\u6CE1\u6CAB\uFF0C\u8E0F\u8DB3\u67D4\u8F6F\u7684\u6C99\u6EE9\uFF08\u4E0E\u8E29\u5728\u957F\u6C99\u7684\u96EA\u5730\u91CC\u6709\u51E0\u5206\u76F8\u4F3C\uFF09\u3002\u53A6\u95E8\u601D\u660E\u533A\u7684\u5EFA\u7B51\u88C5\u6F62\uFF0C\u65E0\u4E0D\u6709\u7740\u522B\u81F4\u7684\u6587\u827A\u8303\uFF0C\u7ACB\u4EA4\u6865\u58A9\u4E0A\u722C\u6EE1\u7684\u85E4\u8513\uFF0C\u51AC\u65E5\u91CC\u4ECD\u7136\u7FE0\u7EFF\u7684\u6811\u53F6\uFF0C\u6709\u65F6\u771F\u7684\u4F1A\u4EA7\u751F\u8EAB\u5904\u5F02\u56FD\u4ED6\u4E61\u7684\u604D\u60DA\u4E4B\u611F\u3002</p><div style="text-align:center;"><img alt="\u6D77\u6D6A\u4E0E\u5915\u9633" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/xiamen_day1_2.jpg" width="60%" height="60%"></div><h3 id="day-2-2022-01-17" tabindex="-1"><a class="header-anchor" href="#day-2-2022-01-17" aria-hidden="true">#</a> Day 2\uFF082022/01/17\uFF09</h3><p>\u65E9\u8D77\u52A8\u8EAB\u690D\u7269\u56ED\uFF0C\u4EC5\u4EC5\u4F5C\u4E3A\u81EA\u7136\u666F\u89C2\u7684\u89C2\u8D4F\uFF0C\u62D3\u5C55\u773C\u754C\uFF0C\u5E76\u65E0\u611F\u53EF\u53D1\u3002</p><p>\u4E2D\u5348\uFF0C\u5728\u53D4\u53D4\u7684\u63A8\u8350\u4E0B\u54C1\u5C1D\u5C01\u8089\uFF0C\u59DC\u6BCD\u9E2D\uFF0C\u83DC\u54C1\u672C\u8EAB\u6781\u5BCC\u53A6\u95E8\u672C\u5730\u7279\u8272\uFF0C\u9910\u5385\u91CC\u6709\u4EBA\u5728\u4F83\u4F83\u800C\u8C08\u4ECA\u65E5\u7684\u80A1\u7968\u8BC1\u5238\u5F62\u5F0F\uFF0C\u6709\u65C5\u5BA2\u4E0E\u6211\u4EEC\u4E00\u6837\u6155\u540D\u800C\u6765\uFF0C\u9910\u5385\u5916\uFF0C\u662F\u53A6\u95E8\u8001\u57CE\u533A\u522B\u5177\u4E00\u683C\u7684\u8857\u9053\uFF0C\u90E8\u5206\u77F3\u7070\u8131\u843D\u7684\u767D\u5899\uFF0C\u5899\u4F53\u4E0A\u51F8\u8D77\u7684\u5BF9\u79F0\u82B1\u7EB9\uFF0C\u6765\u6765\u5F80\u5F80\u7684\u53A6\u95E8\u672C\u5730\u4EBA\u624B\u63D0\u852C\u83DC\u51C6\u5907\u5F52\u5BB6\uFF0C\u90FD\u6210\u4E3A\u90A3\u4E00\u6761\u8857\u9053\u72EC\u6709\u7684\u666F\u8272\u3002\u5F53\u7136\u5C11\u4E0D\u4E86\u7684\u662F\u9694\u58C1\u8001\u5267\u573A\u516C\u56ED\uFF0C\u77F3\u51F3\u77F3\u684C\u9519\u843D\u6709\u81F4\u7684\u6392\u653E\uFF0C\u5DF2\u88AB\u78E8\u53BB\u8868\u9762\u629B\u5149\u6F06\u7684\u6728\u8D28\u957F\u6905\uFF0C\u6709\u8001\u4EBA\u5E26\u7740\u5B69\u5B50\u5728\u5E7F\u573A\u4E0A\u8E22\u76AE\u7403\uFF0C\u6709\u91D1\u8272\u6BDB\u53D1\u7684\u6C6A\u661F\u4EBA\u4E0E\u5B69\u5B50\u4E00\u540C\u5B09\u620F\uFF0C\u90A3\u91CC\uFF0C\u201C\u5546\u4E1A\u201D\u201C\u65C5\u6E38\u201D\u201C\u6253\u5361\u201D\u8FD9\u4E9B\u73B0\u4EE3\u5316\u7684\u540D\u8BCD\u90FD\u88AB\u62B9\u53BB\uFF0C\u7559\u4E0B\u7684\u662F\u60A0\u95F2\u7684\u751F\u6D3B\u6C14\u606F\uFF0C\u66FE\u7ECF\u5728\u6B64\u5904\u770B\u620F\u5267\u7684\u5B69\u5B50\u4ECA\u5929\u6216\u8BB8\u5DF2\u7ECF\u6B65\u5165\u793E\u4F1A\uFF0C\u4F46\u8FD9\u91CC\u72EC\u4E00\u65E0\u4E8C\u7684\u60A0\u60A0\u751F\u6D3B\u6C14\uFF0C\u4E00\u76F4\u88AB\u4FDD\u7559\u5230\u4E86\u6B64\u523B\uFF0C\u5E76\u4E14\u6E29\u67D4\u5730\u629A\u6478\u7740\u4ECA\u5929\u7684\u8001\u620F\u5267\u516C\u56ED\u3002</p><p>\u665A\u4E0A\uFF0C\u5728\u53D4\u53D4\u7684\u5E26\u9886\u4E0B\u91CD\u6E38\u6C99\u5761\u5C3E\uFF0C\u6D77\u4E0A\u89C2\u666F\u5E73\u53F0\u548C\u4E16\u8D38\u5546\u573A\u4E00\u89C8\u6D77\u666F\uFF0C\u6F33\u5DDE\u706F\u5854\u3001\u53A6\u6F33\u5927\u6865\u3001\u9F13\u6D6A\u5C7F\u3001\u90D1\u6210\u529F\u50CF\u540C\u65F6\u6620\u5165\u773C\u5E18\uFF0C\u9001\u738B\u8239\u7684\u95FD\u5357\u6587\u5316\uFF0C\u82B1\u86E4\u9C7F\u9C7C\u548C\u867E\u7684\u9C9C\u5473\u5F25\u6F2B\u53E3\u8154\uFF0C\u6C99\u5761\u5C3E\u827A\u672F\u897F\u533A\u7684\u5F69\u8679\u6808\u9053\uFF0C\u6696\u9EC4\u8272\u7684\u706F\u5149\u4EA4\u7EC7\u91CD\u53E0\uFF0C\u4E00\u8D77\u6784\u6210\u4E86\u8FD9\u91CC\u72EC\u6709\u7684\u6587\u8303\u548C\u827A\u672F\u98CE\u3002\u8FD9\u91CC\u8FD8\u6709\u5C5E\u4E8E\u9752\u5E74\u7684\u98D2\u723D\u6ED1\u677F\uFF0C\u7CBE\u81F4\u7684\u6587\u521B\u5E97\uFF0C\u4ECE\u65E7\u5DE5\u4E1A\u65F6\u4EE3\u9505\u7089\u623F\u6539\u9020\u800C\u6210\u7684\u9152\u5427\uFF0C\u7528\u706F\u6761\u7ED8\u5236\u6210\u7684\u201CBeer\u201D\uFF0C\u5927\u7B14\u4E00\u6325\u753B\u6210\u7684\u8857\u5934\u6D82\u9E26\uFF0C\u90FD\u5145\u6EE1\u4E86\u4E00\u4E2A\u9752\u5E74\u4EBA\u7684\u6D3B\u529B\u548C\u52A8\u611F\u3002\u53A6\u95E8\uFF0C\u4E0D\u5177\u6709\u4E00\u5EA7\u7ECF\u6D4E\u7279\u533A\u7684\u201C\u7E41\u534E\u201D\u548C\u73B0\u4EE3\u5316\uFF0C\u8FD9\u91CC\uFF0C\u662F\u5C5E\u4E8E\u4E00\u5EA7\u6D77\u5C9B\u7684\u7F24\u7EB7\uFF0C\u8FD9\u91CC\u662F\u9752\u5E74\u4EBA\u7684\u57CE\u5E02\u3002</p><p>\u6D77\u98CE\u5439\u62C2\uFF0C\u6D77\u6EE9\u4E0A\u5B69\u5B50\u73A9\u5177\u7684\u706F\u5149\u5728\u95EA\u70C1\uFF0C\u516C\u8DEF\u4E0A\u7684\u6C7D\u8F66\u4E0D\u591A\uFF0C\u505C\u4E0B\u5171\u4EAB\u5355\u8F66\uFF0C\u4E70\u4E00\u7897\u6C34\u679C\u635E\uFF0C\u56DE\u6C11\u5BBF\uFF0C\u5728\u5E8A\u4E0A\u6253\u4E0B\u8FD9\u4E9B\u6587\u5B57\uFF0C\u5173\u706F\uFF0C\u8FDB\u5165\u68A6\u4E61\u3002\u4E00\u5EA7\u57CE\u5E02\u4ECE\u5B81\u9759\u4E2D\u82CF\u9192\uFF0C\u6700\u7EC8\u5728\u60EC\u610F\u7684\u6D77\u98CE\u4E2D\u5F52\u4E8E\u5B81\u9759\u3002\u7CBE\u81F4\uFF0C\u6D3B\u529B\uFF0C\u662F\u53A6\u95E8\u6587\u5316\u7684\u5370\u8BB0\u3002</p><p>\u975E\u5E38\u611F\u8C22\u53D4\u53D4\u4ECA\u665A\u7684\u8BB2\u89E3\u5440\uFF0C\u770B\u5230\u4E86\u53A6\u95E8\u8FD9\u5EA7\u57CE\u66FE\u7ECF\u7684\u8FC7\u5F80\uFF0C\u4E00\u4E9B\u6B64\u523B\u770B\u4E0D\u5230\u7684\u6587\u5316\u4E60\u4FD7\uFF0C\u518D\u6B21\u7531\u8877\u5730\u611F\u8C22\uFF01</p><div style="text-align:center;"><img alt="\u53A6\u95E8\u56DE\u9996" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/xiamen_day2_1.jpg" width="60%" height="60%"></div><h3 id="\u53A6\u95E8\u4E0E\u957F\u6C99\u5BF9\u6BD4" tabindex="-1"><a class="header-anchor" href="#\u53A6\u95E8\u4E0E\u957F\u6C99\u5BF9\u6BD4" aria-hidden="true">#</a> \u53A6\u95E8\u4E0E\u957F\u6C99\u5BF9\u6BD4</h3><p>\u867D\u7136\u90FD\u662F\u7ECF\u6D4E\u6781\u5EA6\u53D1\u8FBE\u7684\u57CE\u5E02\uFF0C\u4F46\u6F2B\u5E03\u4E8E\u4E24\u5EA7\u57CE\u5E02\u7684\u8857\u9053\u95F4\uFF0C\u4F60\u80FD\u611F\u53D7\u5230\u4E24\u5EA7\u57CE\u5E02\u4E0D\u4E00\u6837\u7684\u7CBE\u795E\u5185\u6DB5</p><h4 id="\u53A6\u95E8-1" tabindex="-1"><a class="header-anchor" href="#\u53A6\u95E8-1" aria-hidden="true">#</a> \u53A6\u95E8</h4><p>\u4E00\u5EA7\u6EE8\u6D77\u5C0F\u9547\uFF0C\u4E00\u6E7E\u6E29\u6696\u6E2F\u53E3</p><p>\u6F2B\u6B65\u4E8E\u6C99\u5761\u5C3E\u7684\u5F69\u8679\u6808\u9053\u4E0A\uFF0C\u9001\u738B\u8239\u9759\u9759\u505C\u6CCA\u5728\u6251\u6EE1\u6708\u5149\u7684\u6CB3\u6C34\u4E0A\uFF0C\u5CB8\u8FB9\u7684\u5E97\u5BB6\u70B9\u7740\u706F\uFF0C\u4E0D\u55A7\u95F9\u3001\u5B81\u9759\uFF0C\u6E38\u5BA2\u4E0D\u662F\u5F88\u591A\uFF0C\u867D\u7136\u90FD\u4EE5\u6B63\u5E38\u58F0\u97F3\u8BF4\u7740\u8BDD\uFF0C\u4F46\u591C\u91CC\u7684\u6E56\u6C34\uFF0C\u6726\u80E7\u7684\u591C\u8272\uFF0C\u90FD\u5DE7\u5999\u5730\u5C06\u58F0\u97F3\u5438\u7EB3\u5305\u5BB9\uFF0C\u4E00\u5207\u663E\u5F97\u5B81\u9759\u5B89\u8BE6\u3002\u9152\u5427\uFF0C\u5496\u5561\u5385\uFF0C\u8FD8\u6709\u5145\u6EE1\u6587\u827A\u8272\u5F69\u7684\u6D82\u9E26\u8BBE\u8BA1\uFF0C\u4E00\u5207\u6070\u5230\u597D\u5904\uFF0C\u4ECE\u5BB9\u4E0D\u8FEB\uFF0C\u6162\uFF0C\u8EAB\u5FC3\u5F97\u4EE5\u6C89\u6DC0\u3002</p><p>\u4F46\u63A8\u5F00\u95E8\u8FDB\u53BB\u5462\uFF1F\u53C8\u662F\u4E00\u7247\u4E16\u754C\uFF0C\u4EBA\u58F0\u5435\u95F9\uFF0C\u8BF4\u8BDD\u58F0\uFF0C\u52FA\u5B50\u4E0E\u74F7\u7897\u78B0\u649E\u58F0\uFF0C\u4E0D\u77E5\u54EA\u53C8\u6709\u4EBA\u7B49\u7684\u4E0D\u8010\u70E6\u4E86\uFF0C\u62DB\u547C\u670D\u52A1\u5458\u50AC\u4FC3\u7740\u5FEB\u70B9\u4E0A\u83DC\uFF0C\u65B0\u8FDB\u5E97\u7684\u5BA2\u4EBA\u6162\u6162\u60A0\u60A0\u5730\u9009\u62E9\u7740\u83DC\u54C1\uFF0C\u6392\u961F\u5728\u540E\u9762\u7684\u4EBA\u5F20\u5934\u63A2\u8111\u7B49\u4E0D\u53CA\u3002\u662F\u6DF7\u6C8C\u7684\u4EBA\u95F4\u58F0\u54CD\uFF0C\u662F\u4E0D\u540C\u4EBA\u5EF6\u5C55\u51FA\u7684\u65F6\u7A7A\u91CD\u53E0\u3002</p><div style="text-align:center;"><img alt="\u6C99\u5761\u5C3E\u4E0E\u9001\u738B\u8239" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/xiamen_part3_1.jpg" width="60%" height="60%"></div><h4 id="\u957F\u6C99" tabindex="-1"><a class="header-anchor" href="#\u957F\u6C99" aria-hidden="true">#</a> \u957F\u6C99</h4><p>\u5750\u843D\u4E8E\u8E81\u52A8\u4E0E\u55A7\u95F9\u95F4\u8FFD\u6C42\u6781\u81F4\u7684\u7075\u9B42</p><p>\u8FA3\u5473\u76F4\u523A\u53E3\u8154\u7684\u6E58\u83DC\u6587\u5316\uFF0C\u4EBA\u7FA4\u6512\u52A8\u7684\u73B0\u4EE3\u5316\u8857\u5934\uFF0C\u53E4\u8272\u53E4\u9999\u7684\u8336\u989C\u60A6\u8272\uFF0C\u662F\u957F\u6C99\u7684\u5370\u8BB0\u3002\u957F\u6C99\u8FD9\u5EA7\u57CE\u5E02\uFF0C\u662F\u8FFD\u6C42\u201C\u6781\u81F4\u201D\u7684\u2014\u2014\u8981\u5403\u8FA3\uFF0C\u90A3\u8FA3\u5EA6\u4E00\u5B9A\u8981\u62FC\u5230\u5168\u56FD\u6700\u8FA3\uFF0C\u4E0E\u56DB\u5DDD\u7684\u8FA3\u5473\u513F\u76F8\u5DEE\u65E0\u51E0\uFF08\u636E\u540C\u5B66\u6240\u8A00\uFF0C8\u6708\u4EFD\u4EB2\u81EA\u53BB\u8003\u8BC1\u8003\u8BC1~\uFF09\uFF1B\u8981\u201C\u5546\u573A\u201D\uFF0C\u90A3\u4E5F\u8981\u5168\u7403\u6700\u5927\u7684\u5355\u4F53\u5EFA\u7B51\u2014\u2014\u4E07\u5BB6\u4E3D\uFF0C\u505A\u4E00\u4E2A\u8D85\u7EA7\u5546\u57CE\uFF1B\u8981\u201C\u73B0\u4EE3\u5316\u201D\uFF0C\u90A3\u4E5F\u4E00\u5B9A\u8981\u662F\u76F4\u7A7F\u4E91\u9704\u7684\u6469\u5929\u5927\u697C\uFF0C\u7EDA\u70C2\u593A\u76EE\u7684\u9713\u8679\u706F\uFF1B\u8981\u201C\u7ECF\u6D4E\u53D1\u5C55\u201D\u201C\u53E4\u8272\u53E4\u9999\u201D\uFF0C\u90A3\u4E5F\u662F\u5145\u6EE1\u53E4\u97F5\u7684\u8336\u989C\u60A6\u8272\u4EE5\u5976\u8336\u4E3A\u8F7D\u4F53\u5145\u65A5\u7740\u6574\u5EA7\u57CE\u5E02\u7684\u6BCF\u4E00\u4E2A\u5546\u4E1A\u89D2\u843D\u3002</p><div style="text-align:center;"><img alt="\u7EDA\u70C2\u593A\u76EE\u7684\u9713\u8679\u706F" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/xiamen_part3_2.jpg" width="60%" height="60%"></div><div style="text-align:center;"><img alt="\u76F4\u7A7F\u4E91\u9704\u7684\u6469\u5929\u5927\u53A6" src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/xiamen_part3_3.jpg" width="60%" height="60%"></div><p>\u8FD9\u6837\u7684\u8FFD\u6C42\u6781\u81F4\uFF0C\u8FD9\u6837\u7684\u8E81\u52A8\uFF0C\u8BA9\u957F\u6C99\u5FEB\u901F\u6210\u4E3A\u7F51\u7EA2\u57CE\u5E02\uFF0C\u5982\u6B64\uFF0C\u53C8\u662F\u4E00\u6CE2\u53C8\u4E00\u6CE2\u5916\u5730\u4EBA\u6D8C\u5165\u957F\u6C99\uFF0C\u8857\u9053\u53D8\u5F97\u62E5\u5835\uFF0C\u51FA\u95E8\u4E0D\u662F\u626B\u8857\uFF0C\u4FBF\u662F\u770B\u4EBA\u6D77\u4E86\uFF0C\u751A\u81F3\u81EA\u5DF1\u4E5F\u6DF7\u5165\u5176\u4E2D\u6210\u4E3A\u201C\u4EBA\u6D77\u201D\u4E2D\u7684\u4E00\u7C92\u5C0F\u201C\u4EBA\u6EF4\u201D\u2026\u2026</p><h2 id="\u6D4F\u9633" tabindex="-1"><a class="header-anchor" href="#\u6D4F\u9633" aria-hidden="true">#</a> \u6D4F\u9633</h2><p>\u65C5\u884C\u4E0D\u662F\u7D27\u8FEB\u7684\u65E5\u7A0B\uFF0C\u800C\u662F\u6700\u666E\u901A\u7684\u751F\u6D3B\u65E5\u5E38\u3002</p><h3 id="day-1-2022-08-01" tabindex="-1"><a class="header-anchor" href="#day-1-2022-08-01" aria-hidden="true">#</a> Day 1\uFF082022/08/01\uFF09</h3><p>2022.07.31 \u665A23\u65F6\uFF0C\u4ECE\u5BBF\u820D\u51FA\u53D1\u62B5\u8FBE\u6D4F\u9633\u3002</p><p>\u4F4F\u5728\u540C\u5B66\u5BB6\u4E2D\uFF0C\u751A\u662F\u8212\u9002\u3002\u65E9\u6668\u61D2\u61D2\u5730\u8D77\u5E8A\uFF0C\u52A8\u8EAB\u9762\u9986\uFF0C\u5E97\u4E3B\u4E0E\u540C\u5B66\u7528\u5730\u9053\u7684\u6D4F\u9633\u672C\u5730\u8BDD\u4EA4\u6D41\u7740\uFF0C\u9762\u6761\u5728\u53A8\u5E08\u7684\u624B\u91CC\u821E\u52A8\uFF0C\u5E97\u91CC\u88C5\u6F62\u5F88\u65B0\uFF0C\u636E\u4E86\u89E3\u624D\u5F97\u77E5\u662F\u521A\u642C\u8FDB\u4E0D\u4E45\uFF0C\u4F46\u662F\u5BB6\u8001\u5E97\u3002\u6D4F\u9633\u672C\u5730\u4EBA\u5728\u8FD9\u5BB6\u5E97\u8FDB\u8FDB\u51FA\u51FA\uFF0C\u6CA1\u6709\u5E74\u8F7B\u4EBA\u7684\u8EAB\u5F71\u4E5F\u6CA1\u6709\u76F4\u64ADlive\u7684\u6444\u50CF\u5934\uFF0C\u4E0D\u50CF\u662F\u65C5\u5BA2\u4F1A\u524D\u6765\u7684\u6253\u5361\u70B9\u3002</p><p>\u996D\u540E\u4E8E\u8857\u5934\u5F98\u5F8A\uFF0C\u6F2B\u5E03\u4E8E\u5929\u8679\u8D85\u5E02\uFF0C\u9A91\u8F66\u4E8E\u6B65\u884C\u8857\uFF0C\u9014\u5F84\u6587\u5E99\u3001\u8C2D\u55E3\u540C\u6545\u5C45\uFF0C\u8FD9\u6837\u6D41\u6C34\u8D26\u7684\u8BB0\u5F55\u65B9\u5F0F\u4E0D\u514D\u843D\u5165\u201C\u5C0F\u5B66\u751F\u4F5C\u6587\u201D\u7684\u5FCC\u8BB3\uFF0C\u4F46\u8FD9\u6837\u7684\u6162\uFF0C\u662F\u6211\u6240\u4EAB\u53D7\u548C\u73CD\u60DC\u7684\u3002</p><p>\u624B\u6367\u4E00\u676F\u8336\u989C\uFF0C\u5976\u8336\u7684\u9187\u9999\u6D41\u8FDB\u53E3\u8154\uFF0C\u5916\u9762\u662F\u70C8\u65E5\u5F53\u5934\uFF0C\u7A7A\u8C03\u623F\u91CC\u6211\u6253\u5F00\u7535\u8111\u6572\u4E0B\u8FD9\u4E9B\u6587\u5B57\uFF0C\u8BB0\u5F55\u4E0B\u4E00\u5929\u7684\u884C\u7A0B\u3002</p><div style="text-align:center;"><img src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/liuyang_day1_1.jpg" width="60%" height="60%"></div><div style="text-align:center;"><img src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/liuyang_day1_2.jpg" width="60%" height="60%"></div><p>\u4E0B\u5348\u524D\u53BB\u6F02\u6D41\uFF0C\u7531\u4E8E\u624B\u673A\u7981\u6B62\u5E26\u4E0A\u8239\uFF0C\u53C8\u6CA1\u6709go pro\u8FD0\u52A8\u76F8\u673A\uFF0C\u5C31\u6CA1\u6709\u7167\u7247\u8BB0\u5F55\u5566\uFF0C\u4F46\u662F\u4E0D\u7BA1\u600E\u4E48\u8BF4\uFF0C\u7B97\u662F\u4E00\u4E2A\u96BE\u5F97\u7684\u56DE\u5FC6\u5427\uFF01\u6700\u540E35\u7C73\u5927\u843D\u5DEE\u7684\u6ED4\u5929\u5DE8\u6D6A\u8FD8\u662F\u6709\u70B9\u523A\u6FC0\u7684\uFF01</p><h3 id="day-2-2022-08-02" tabindex="-1"><a class="header-anchor" href="#day-2-2022-08-02" aria-hidden="true">#</a> Day 2\uFF082022/08/02\uFF09</h3><ul><li><strong>\u8BBF\u95EE\u535A\u7269\u9986\uFF0C\u56FE\u4E66\u9986</strong></li></ul><p>\u8E0F\u5165\u4E00\u5EA7\u7EA2\u8272\u57CE\u5E02\u7684\u5386\u53F2\uFF0C\u89E6\u6478\u9769\u547D\u5148\u70C8\u7684\u5370\u8BB0\u3002</p><p>\u8E0F\u5165\u5F00\u56FD\u529F\u52CB\u7684\u5C55\u5385\uFF0C\u65B9\u624D\u610F\u8BC6\u5230\u8FD9\u5EA7\u535A\u7269\u9986\u7684\u4E0E\u4F17\u4E0D\u540C\u3002\u5927\u6C14\u7684\u201C\u4EBA\u6C11\u82F1\u96C4\u6C38\u5782\u4E0D\u673D\u201D\u88AB\u6D53\u58A8\u91CD\u5F69\u5730\u4E66\u5199\u5728\u6574\u95F4\u5C55\u5385\u6700\u6B63\u4E2D\u95F4\u7684\u7EA2\u5899\u4E0A\uFF0C\u91D1\u9EC4\u8272\u7684\u5927\u5B57\u914D\u5408\u5BBD\u5927\u5149\u6ED1\u7684\u5927\u7406\u77F3\u74F7\u7816\uFF0C\u5728\u955C\u9762\u4E16\u754C\u4E2D\u5448\u73B0\u5BF9\u79F0\u4E0E\u5B8F\u4F1F\u7684\u58EE\u9614\uFF0C\u5982\u540C\u590F\u591C\u665A\u4E0A\u7684\u6E56\u9762\u822C\u6D01\u51C0\uFF0C\u5B89\u5B81\uFF0C\u9EC4\u82B1\u3001\u767D\u82B1\u88AB\u89C4\u6574\u5730\u653E\u5728\u91D1\u8272\u5927\u5B57\u7684\u4E0B\u8FB9\uFF0C\u795D\u613F\u5B89\u846C\u5728\u8FBD\u9614\u795E\u5DDE\u5927\u5730\u4E0B\u7684\u70C8\u58EB\u4EEC\u7761\u5F97\u5B89\u8BE6\u3002\u5C55\u5385\u7684\u4E24\u4FA7\u662F\u523B\u6EE1\u540D\u5B57\u7684\u70C8\u58EB\u5899\uFF0C\u9C9C\u7EA2\u7684\u540D\u5B57\u5982\u9C9C\u7EA2\u7684\u523A\u67AA\uFF0C\u4ED6\u4EEC\u66FE\u7ECF\u5411\u7740\u654C\u4EBA\u731B\u70C8\u8FDB\u653B\uFF0C\u73B0\u5728\u4E00\u6B21\u6B21\u63D0\u9192\u6211\uFF0C\u8BA9\u6211\u65E0\u6CD5\u9057\u5FD8\u8FC7\u53BB\u3002\u5730\u4E0B\u7684\u5FE0\u9AA8\u554A\uFF0C\u4F60\u4EEC\u7684\u540D\u5B57\u4F1A\u88AB\u94ED\u8BB0\uFF0C\u5373\u4F7F\u6765\u5E74\u5C71\u65E0\u68F1\uFF0C\u5929\u5730\u5408\uFF0C\u6211\u4E5F\u4E0D\u6562\u4E0E\u541B\u8BC0\u522B\uFF01</p><div style="text-align:center;"><img src="https://cdn.statically.io/gh/dream-oyh/dream-oyh.github.io/images/liuyang_day2_1.jpg" width="60%" height="60%"></div><p>Goodbye\uFF0C\u6D4F\u9633\uFF0C\u6709\u673A\u4F1A\u518D\u89C1\uFF01</p>',45),r=[d];function n(s,p){return e(),i("div",null,r)}var g=a(h,[["render",n],["__file","tour.html.vue"]]);export{g as default};
